package com.example.search.service;

import com.example.search.model.Product;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.ElasticsearchStatusException;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.support.WriteRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.client.indices.PutMappingRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.List;
import java.util.Map;

@Service
public class ProductIndexService {

    public static final String DEFAULT_PRODUCTS_INDEX = "products";
    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;
    private final String productsIndex;

    public ProductIndexService(RestHighLevelClient client,
                              ObjectMapper objectMapper,
                              @Value("${elasticsearch.index.products:products}") String productsIndex) {
        this.client = client;
        this.objectMapper = objectMapper;
        this.productsIndex = productsIndex;
    }

    public String getProductsIndex() {
        return productsIndex;
    }

    public void ensureProductsIndex() throws IOException {
        boolean exists = client.indices().exists(new GetIndexRequest(productsIndex), RequestOptions.DEFAULT);
        if (exists) return;

        CreateIndexRequest req = new CreateIndexRequest(productsIndex);
        req.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0)
                .put("analysis.analyzer.folded.type", "custom")
                .put("analysis.analyzer.folded.tokenizer", "standard")
                .putList("analysis.analyzer.folded.filter", "lowercase", "asciifolding")
        );

        String mapping = "{\n" +
                "  \"dynamic\": true,\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"sku\": {\"type\": \"keyword\"},\n" +
                "    \"name\": {\"type\": \"text\", \"analyzer\": \"folded\", \"fields\": {\"keyword\": {\"type\": \"keyword\", \"ignore_above\": 256}}},\n" +
                "    \"description\": {\"type\": \"text\", \"analyzer\": \"folded\"},\n" +
                "    \"brand\": {\"type\": \"keyword\"},\n" +
                "    \"categories\": {\"type\": \"keyword\"},\n" +
                "    \"tags\": {\"type\": \"keyword\"},\n" +
                "    \"price\": {\"type\": \"scaled_float\", \"scaling_factor\": 100},\n" +
                "    \"currency\": {\"type\": \"keyword\"},\n" +
                "    \"inStock\": {\"type\": \"boolean\"},\n" +
                "    \"rating\": {\"type\": \"half_float\"},\n" +
                "    \"reviewCount\": {\"type\": \"integer\"},\n" +
                "    \"attributes\": {\"type\": \"flattened\"},\n" +
                "    \"createdAt\": {\"type\": \"date\"},\n" +
                "    \"updatedAt\": {\"type\": \"date\"}\n" +
                "  }\n" +
                "}";
        req.mapping(mapping, XContentType.JSON);

        client.indices().create(req, RequestOptions.DEFAULT);
    }

    public void recreateProductsIndex() throws IOException {
        try {
            client.indices().delete(new DeleteIndexRequest(productsIndex), RequestOptions.DEFAULT);
        } catch (ElasticsearchStatusException e) {
            // ignore
        }
        ensureProductsIndex();
    }

    public void indexProduct(Product product) throws IOException {
        if (product.getCreatedAt() == null) product.setCreatedAt(Instant.now());
        product.setUpdatedAt(Instant.now());

        Map<String, Object> src = objectMapper.convertValue(product, new TypeReference<Map<String, Object>>() {});
        IndexRequest req = new IndexRequest(productsIndex)
                .id(product.getId())
                .source(src)
                .setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);

        client.index(req, RequestOptions.DEFAULT);
    }

    public BulkResponse bulkIndex(List<Product> products) throws IOException {
        BulkRequest bulk = new BulkRequest();
        for (Product p : products) {
            if (p.getCreatedAt() == null) p.setCreatedAt(Instant.now());
            p.setUpdatedAt(Instant.now());
            Map<String, Object> src = objectMapper.convertValue(p, new TypeReference<Map<String, Object>>() {});
            bulk.add(new IndexRequest(productsIndex).id(p.getId()).source(src));
        }
        bulk.setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);
        return client.bulk(bulk, RequestOptions.DEFAULT);
    }

    public boolean isBulkSuccessful(BulkResponse response) {
        return response != null && !response.hasFailures();
    }
}

package com.example.search.service;

import com.example.search.model.SearchQueryLog;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.support.WriteRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.Map;
import java.util.UUID;

@Service
public class SearchQueryLogService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;
    private final String queriesIndex;

    public SearchQueryLogService(RestHighLevelClient client,
                                 ObjectMapper objectMapper,
                                 @Value("${elasticsearch.index.queries:search_queries}") String queriesIndex) {
        this.client = client;
        this.objectMapper = objectMapper;
        this.queriesIndex = queriesIndex;
    }

    public void log(SearchQueryLog log) {
        try {
            if (log.getId() == null) log.setId(UUID.randomUUID().toString());
            if (log.getTimestamp() == null) log.setTimestamp(Instant.now());

            Map<String, Object> src = objectMapper.convertValue(log, new TypeReference<Map<String, Object>>() {});
            IndexRequest req = new IndexRequest(queriesIndex)
                    .id(log.getId())
                    .source(src)
                    .setRefreshPolicy(WriteRequest.RefreshPolicy.NONE);

            client.index(req, RequestOptions.DEFAULT);
        } catch (IOException ignored) {
        }
    }
}

package com.example.search.service;

import com.example.search.dto.ProductSearchRequest;
import com.example.search.dto.ProductSearchResponse;
import com.example.search.model.Product;
import com.example.search.model.SearchQueryLog;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.Operator;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.range.RangeAggregationBuilder;
import org.elasticsearch.search.aggregations.bucket.terms.TermsAggregationBuilder;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortBuilders;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.stereotype.Service;
import org.springframework.util.StringUtils;

import java.io.IOException;
import java.math.BigDecimal;
import java.util.*;

@Service
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;
    private final ProductIndexService productIndexService;
    private final SearchQueryLogService queryLogService;

    public ProductSearchService(RestHighLevelClient client,
                                ObjectMapper objectMapper,
                                ProductIndexService productIndexService,
                                SearchQueryLogService queryLogService) {
        this.client = client;
        this.objectMapper = objectMapper;
        this.productIndexService = productIndexService;
        this.queryLogService = queryLogService;
    }

    public ProductSearchResponse search(ProductSearchRequest req, String userId, String sessionId, String userAgent, String ip) throws IOException {
        int page = req.getPage() == null ? 0 : Math.max(0, req.getPage());
        int size = req.getSize() == null ? 20 : Math.min(200, Math.max(1, req.getSize()));
        int from = page * size;

        BoolQueryBuilder bool = QueryBuilders.boolQuery();

        if (StringUtils.hasText(req.getQ())) {
            MultiMatchQueryBuilder mm = QueryBuilders.multiMatchQuery(req.getQ(), "name^4", "description^1", "brand^2", "tags^2")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .operator(Operator.AND)
                    .fuzziness("AUTO");
            bool.must(mm);
        } else {
            bool.must(QueryBuilders.matchAllQuery());
        }

        if (req.getCategories() != null && !req.getCategories().isEmpty()) {
            bool.filter(QueryBuilders.termsQuery("categories", req.getCategories()));
        }
        if (req.getBrands() != null && !req.getBrands().isEmpty()) {
            bool.filter(QueryBuilders.termsQuery("brand", req.getBrands()));
        }
        if (req.getTags() != null && !req.getTags().isEmpty()) {
            bool.filter(QueryBuilders.termsQuery("tags", req.getTags()));
        }
        if (req.getInStock() != null) {
            bool.filter(QueryBuilders.termQuery("inStock", req.getInStock()));
        }

        BigDecimal minPrice = req.getMinPrice();
        BigDecimal maxPrice = req.getMaxPrice();
        if (minPrice != null || maxPrice != null) {
            var range = QueryBuilders.rangeQuery("price");
            if (minPrice != null) range.gte(minPrice);
            if (maxPrice != null) range.lte(maxPrice);
            bool.filter(range);
        }

        if (req.getAttributes() != null && !req.getAttributes().isEmpty()) {
            for (Map.Entry<String, List<String>> e : req.getAttributes().entrySet()) {
                String key = e.getKey();
                List<String> values = e.getValue();
                if (!StringUtils.hasText(key) || values == null || values.isEmpty()) continue;
                bool.filter(QueryBuilders.termsQuery("attributes." + key, values));
            }
        }

        SearchSourceBuilder ssb = new SearchSourceBuilder()
                .query(bool)
                .from(from)
                .size(size)
                .trackTotalHits(true);

        applySort(req, ssb);

        TermsAggregationBuilder brandAgg = AggregationBuilders.terms("facet_brand").field("brand").size(50);
        TermsAggregationBuilder categoryAgg = AggregationBuilders.terms("facet_categories").field("categories").size(50);
        TermsAggregationBuilder tagsAgg = AggregationBuilders.terms("facet_tags").field("tags").size(50);

        RangeAggregationBuilder priceAgg = AggregationBuilders.range("facet_price")
                .field("price")
                .addRange("0-25", 0, 25)
                .addRange("25-50", 25, 50)
                .addRange("50-100", 50, 100)
                .addRange("100-200", 100, 200)
                .addUnboundedFrom("200+", 200);

        ssb.aggregation(brandAgg);
        ssb.aggregation(categoryAgg);
        ssb.aggregation(tagsAgg);
        ssb.aggregation(priceAgg);

        SearchRequest sreq = new SearchRequest(productIndexService.getProductsIndex()).source(ssb);
        SearchResponse sresp = client.search(sreq, RequestOptions.DEFAULT);

        List<Product> items = new ArrayList<>();
        for (SearchHit hit : sresp.getHits().getHits()) {
            Product p = objectMapper.convertValue(hit.getSourceAsMap(), Product.class);
            if (p.getId() == null) p.setId(hit.getId());
            items.add(p);
        }

        Map<String, Object> facets = new LinkedHashMap<>();
        facets.put("brand", aggToBuckets(sresp, "facet_brand"));
        facets.put("categories", aggToBuckets(sresp, "facet_categories"));
        facets.put("tags", aggToBuckets(sresp, "facet_tags"));
        facets.put("price", aggToRanges(sresp, "facet_price"));

        SearchQueryLog log = new SearchQueryLog();
        log.setQuery(req.getQ());
        log.setFilters(buildFiltersForLog(req));
        log.setPage(page);
        log.setSize(size);
        log.setUserId(userId);
        log.setSessionId(sessionId);
        log.setUserAgent(userAgent);
        log.setIp(ip);
        queryLogService.log(log);

        long total = sresp.getHits().getTotalHits() == null ? items.size() : sresp.getHits().getTotalHits().value;
        return new ProductSearchResponse(total, page, size, items, facets);
    }

    private void applySort(ProductSearchRequest req, SearchSourceBuilder ssb) {
        String sortBy = req.getSortBy();
        String sortDir = req.getSortDir();
        SortOrder order = "desc".equalsIgnoreCase(sortDir) ? SortOrder.DESC : SortOrder.ASC;

        if (!StringUtils.hasText(sortBy)) {
            ssb.sort(SortBuilders.scoreSort().order(SortOrder.DESC));
            ssb.sort(SortBuilders.fieldSort("updatedAt").order(SortOrder.DESC).unmappedType("date"));
            return;
        }

        switch (sortBy) {
            case "price":
                ssb.sort(SortBuilders.fieldSort("price").order(order).unmappedType("double"));
                break;
            case "rating":
                ssb.sort(SortBuilders.fieldSort("rating").order(order).unmappedType("double"));
                break;
            case "updatedAt":
                ssb.sort(SortBuilders.fieldSort("updatedAt").order(order).unmappedType("date"));
                break;
            case "name":
                ssb.sort(SortBuilders.fieldSort("name.keyword").order(order).unmappedType("keyword"));
                break;
            default:
                ssb.sort(SortBuilders.scoreSort().order(SortOrder.DESC));
                ssb.sort(SortBuilders.fieldSort("updatedAt").order(SortOrder.DESC).unmappedType("date"));
        }
    }

    private Map<String, Object> buildFiltersForLog(ProductSearchRequest req) {
        Map<String, Object> m = new LinkedHashMap<>();
        if (req.getCategories() != null && !req.getCategories().isEmpty()) m.put("categories", req.getCategories());
        if (req.getBrands() != null && !req.getBrands().isEmpty()) m.put("brands", req.getBrands());
        if (req.getTags() != null && !req.getTags().isEmpty()) m.put("tags", req.getTags());
        if (req.getInStock() != null) m.put("inStock", req.getInStock());
        if (req.getMinPrice() != null) m.put("minPrice", req.getMinPrice());
        if (req.getMaxPrice() != null) m.put("maxPrice", req.getMaxPrice());
        if (req.getAttributes() != null && !req.getAttributes().isEmpty()) m.put("attributes", req.getAttributes());
        if (req.getSortBy() != null) m.put("sortBy", req.getSortBy());
        if (req.getSortDir() != null) m.put("sortDir", req.getSortDir());
        return m;
    }

    private List<Map<String, Object>> aggToBuckets(SearchResponse resp, String aggName) {
        var agg = resp.getAggregations().get(aggName);
        if (!(agg instanceof org.elasticsearch.search.aggregations.bucket.terms.Terms)) return List.of();
        org.elasticsearch.search.aggregations.bucket.terms.Terms terms = (org.elasticsearch.search.aggregations.bucket.terms.Terms) agg;

        List<Map<String, Object>> out = new ArrayList<>();
        for (org.elasticsearch.search.aggregations.bucket.terms.Terms.Bucket b : terms.getBuckets()) {
            Map<String, Object> row = new LinkedHashMap<>();
            row.put("key", b.getKeyAsString());
            row.put("count", b.getDocCount());
            out.add(row);
        }
        return out;
    }

    private List<Map<String, Object>> aggToRanges(SearchResponse resp, String aggName) {
        var agg = resp.getAggregations().get(aggName);
        if (!(agg instanceof org.elasticsearch.search.aggregations.bucket.range.Range)) return List.of();
        org.elasticsearch.search.aggregations.bucket.range.Range range = (org.elasticsearch.search.aggregations.bucket.range.Range) agg;

        List<Map<String, Object>> out = new ArrayList<>();
        for (org.elasticsearch.search.aggregations.bucket.range.Range.Bucket b : range.getBuckets()) {
            Map<String, Object> row = new LinkedHashMap<>();
            row.put("key", b.getKeyAsString());
            row.put("from", b.getFrom());
            row.put("to", b.getTo());
            row.put("count", b.getDocCount());
            out.add(row);
        }
        return out;
    }
}

package com.example.search.controller;

import com.example.search.dto.ProductSearchRequest;
import com.example.search.dto.ProductSearchResponse;
import com.example.search.model.Product;
import com.example.search.service.ProductIndexService;
import com.example.search.service.ProductSearchService;
import org.elasticsearch.action.bulk.BulkResponse;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import jakarta.servlet.http.HttpServletRequest;
import java.io.IOException;
import java.util.List;

@RestController
@RequestMapping("/api")
public class ProductController {

    private final ProductIndexService indexService;
    private final ProductSearchService searchService;

    public ProductController(ProductIndexService indexService, ProductSearchService searchService) {
        this.indexService = indexService;
        this.searchService = searchService;
    }

    @PostMapping("/admin/index/products/ensure")
    public ResponseEntity<Void> ensureIndex() throws IOException {
        indexService.ensureProductsIndex();
        return ResponseEntity.noContent().build();
    }

    @PostMapping("/admin/index/products/recreate")
    public ResponseEntity<Void> recreateIndex() throws IOException {
        indexService.recreateProductsIndex();
        return ResponseEntity.noContent().build();
    }

    @PutMapping("/products/{id}")
    public ResponseEntity<Void> upsertProduct(@PathVariable String id, @RequestBody Product product) throws IOException {
        indexService.ensureProductsIndex();
        product.setId(id);
        indexService.indexProduct(product);
        return ResponseEntity.noContent().build();
    }

    @PostMapping("/products/bulk")
    public ResponseEntity<String> bulkIndex(@RequestBody List<Product> products) throws IOException {
        indexService.ensureProductsIndex();
        BulkResponse resp = indexService.bulkIndex(products);
        if (indexService.isBulkSuccessful(resp)) return ResponseEntity.ok("OK");
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(resp.buildFailureMessage());
    }

    @PostMapping("/products/search")
    public ProductSearchResponse search(@RequestBody ProductSearchRequest req, HttpServletRequest http) throws IOException {
        indexService.ensureProductsIndex();
        String userId = http.getHeader("X-User-Id");
        String sessionId = http.getHeader("X-Session-Id");
        String userAgent = http.getHeader("User-Agent");
        String ip = http.getRemoteAddr();
        return searchService.search(req, userId, sessionId, userAgent, ip);
    }
}

